from typing import List, Dict, Optional, Tuple
from collections import deque
import heapq


class Solution:
    # ---------- Optimal for UNWEIGHTED graphs: BFS ----------
    def shortestPath(self, graph: Dict[str, List[str]],
                     start_node: str, target_node: str) -> Optional[List[str]]:
        if start_node not in graph or target_node not in graph:
            return None
        if start_node == target_node:
            return [start_node]

        visited = {start_node}
        parent = {start_node: None}
        queue = deque([start_node])  # deque = O(1) popleft, plain list pop(0) is O(n)

        while queue:
            current = queue.popleft()
            for neighbor in graph.get(current, []):
                if neighbor not in visited:
                    visited.add(neighbor)
                    parent[neighbor] = current
                    if neighbor == target_node:
                        return self._reconstruct(parent, target_node)
                    queue.append(neighbor)
        return None

    def _reconstruct(self, parent: Dict[str, Optional[str]],
                     target_node: str) -> List[str]:
        path = []
        node = target_node
        while node is not None:
            path.append(node)
            node = parent[node]
        path.reverse()
        return path

    # ---------- Optimal for WEIGHTED (non-negative) graphs: Dijkstra ----------
    def shortestPathWeighted(self, graph: Dict[str, List[Tuple[str, int]]],
                             start_node: str, target_node: str) -> Optional[List[str]]:
        if start_node not in graph or target_node not in graph:
            return None
        dist = {start_node: 0}
        parent = {start_node: None}
        heap = [(0, start_node)]  # min-heap keyed by distance
        settled = set()

        while heap:
            d, current = heapq.heappop(heap)
            if current in settled:
                continue
            settled.add(current)
            if current == target_node:
                return self._reconstruct(parent, target_node)
            for neighbor, w in graph.get(current, []):
                nd = d + w
                if nd < dist.get(neighbor, float('inf')):
                    dist[neighbor] = nd
                    parent[neighbor] = current
                    heapq.heappush(heap, (nd, neighbor))
        return None

    # ---------- Brute-force oracle: DFS all paths, keep shortest ----------
    def shortestPathBrute(self, graph, start_node, target_node):
        best = [None]
        def dfs(node, path, seen):
            if node == target_node:
                if best[0] is None or len(path) < len(best[0]):
                    best[0] = list(path)
                return
            for nb in graph.get(node, []):
                if nb not in seen:
                    seen.add(nb); path.append(nb)
                    dfs(nb, path, seen)
                    path.pop(); seen.remove(nb)
        if start_node not in graph or target_node not in graph:
            return None
        dfs(start_node, [start_node], {start_node})
        return best[0]


# ---------------- Tests ----------------
s = Solution()
g = {"A": ["B", "C"], "B": ["D"], "C": ["D", "E"], "D": ["E"], "E": []}

# Example
print("ex:", s.shortestPath(g, "A", "E"))           # [A, C, E]
print("brute:", s.shortestPathBrute(g, "A", "E"))   # length 3 path also valid, but shortest len

# Edge cases
print("same:", s.shortestPath(g, "A", "A"))          # [A]
print("no path:", s.shortestPath({"A": ["B"], "B": [], "C": []}, "A", "C"))  # None
print("missing:", s.shortestPath(g, "A", "Z"))       # None
print("single edge:", s.shortestPath(g, "A", "B"))   # [A, B]

# Weighted: A-B=1, A-C=4, B-C=1  => A->B->C (2) beats A->C (4)
gw = {"A": [("B", 1), ("C", 4)], "B": [("C", 1)], "C": []}
print("dijkstra:", s.shortestPathWeighted(gw, "A", "C"))  # [A, B, C]

# Oracle agreement on length for random-ish graphs
import random
def rand_graph(n):
    nodes = [str(i) for i in range(n)]
    gg = {x: [] for x in nodes}
    for u in nodes:
        for v in nodes:
            if u != v and random.random() < 0.3:
                gg[u].append(v)
    return gg, nodes

ok = True
for _ in range(2000):
    gg, nodes = rand_graph(6)
    a, b = random.choice(nodes), random.choice(nodes)
    bfs = s.shortestPath(gg, a, b)
    bru = s.shortestPathBrute(gg, a, b)
    la = len(bfs) if bfs else -1
    lb = len(bru) if bru else -1
    if la != lb:
        ok = False
        print("MISMATCH", a, b, bfs, bru, gg)
        break
print("oracle agreement:", ok)
